// Instruction Strategist v8 — Bulletproof + Custom Rules + Global Enforcement
const input = $('Webhook1').first().json.body;

// ─── GLOBAL RULES: Always applied regardless of brief content ────────────────
const GLOBAL_RULES = [
  "Do NOT use AI-sounding filler phrases. Banned phrases: 'Additionally', 'Moreover', 'Furthermore', 'Let\'s dive in', 'In conclusion', 'The bottom line', 'It\'s worth noting', 'Dive into', 'In today\'s world', 'Transitioning to'.",
  "Write in active voice. Do not use passive voice constructions.",
  "Keep paragraphs to 2–3 sentences maximum. Long paragraphs must be broken up.",
  "ANTI-HALLUCINATION PROTOCOL: The client's website is the primary source of truth. If specific information is missing, fall back to general web research. However, if a specific claim, statistic, or percentage cannot be explicitly verified on the client website or reliable internet sources, YOU MUST OMIT IT SMOOTHLY. Do NOT invent or estimate statistics, research studies, percentages, or expert names. Do not use placeholders like [Data Needed] — just write around it naturally without tempering the overall content.",
  "Do not use em-dashes (—). Replace with commas, colons, or restructured sentences.",
  "Do not use generic CTAs like 'Click here' or 'Learn more'. CTAs must be specific and action-oriented.",
  "Every H2 section must contain at least 2 substantive paragraphs. No single-sentence sections.",
  "Do not repeat the same phrase or sentence structure in consecutive paragraphs.",
  "Bold text (**bold**) should be used sparingly — only for genuinely critical terms, not for stylistic emphasis.",
];

function parseKeywords(raw) {
  if (!raw) return [];
  if (Array.isArray(raw)) {
    return raw.flatMap(item => item.split(',').map(k => k.trim())).filter(k => k.length > 0);
  }
  if (typeof raw !== 'string') return [];
  return raw.split(',').map(k => k.trim()).filter(k => k.length > 0);
}

const rawPrimary = input.primary_keywords;
const primary = (Array.isArray(rawPrimary) ? rawPrimary.join(', ') : rawPrimary) || '';
const secondary = parseKeywords(input.secondary_keywords);
const semantic = parseKeywords(input.semantic_themes);

// ─── EXTRACT AI PARSED BRIEF DATA ────────────────────────────────────────────
let aiOutputRAW = $('Parse Creative Brief (LLM)').first().json.message?.content
               || $('Parse Creative Brief (LLM)').first().json.text
               || $('Parse Creative Brief (LLM)').first().json.choices?.[0]?.message?.content
               || '{}';

let aiData = { headings: [], faqs: [], custom_rules: [], tone_instructions: '' };
try {
  if (typeof aiOutputRAW === 'object' && aiOutputRAW !== null) {
    aiData = { headings: [], faqs: [], custom_rules: [], tone_instructions: '', ...aiOutputRAW };
  } else if (typeof aiOutputRAW === 'string') {
    let cleanedRAW = aiOutputRAW;
    cleanedRAW = cleanedRAW.replace(/^[\s\S]*?```json\s*/, '').replace(/```[\s\S]*$/, '').trim();
    cleanedRAW = cleanedRAW.replace(/^[\s\S]*?```\s*/, '').replace(/```[\s\S]*$/, '').trim();
    const match = cleanedRAW.match(/\{[\s\S]*\}/);
    if (match) cleanedRAW = match[0];
    const parsed = JSON.parse(cleanedRAW);
    aiData = { headings: [], faqs: [], custom_rules: [], tone_instructions: '', ...parsed };
  }
} catch (e) {
  console.log('Brief parser JSON parse failed:', e.message);
}

const briefHeadings     = Array.isArray(aiData.headings)      ? aiData.headings      : [];
const faqArray          = Array.isArray(aiData.faqs)          ? aiData.faqs          : [];
const briefCustomRules  = Array.isArray(aiData.custom_rules)  ? aiData.custom_rules  : [];
const briefTone         = typeof aiData.tone_instructions === 'string' ? aiData.tone_instructions : '';

// ─── FAQ INJECTION ────────────────────────────────────────────────────────────
let faqInjection = '';
if (faqArray.length > 0) {
  faqInjection = '### MANDATORY FAQS\n\nAt the end of the article include an FAQ section with EXACTLY these questions. If an answer is provided, incorporate that information into your answer — do not ignore it.\n\n';
  faqArray.forEach(faq => {
    faqInjection += `**Q: ${faq.question}**\n`;
    if (faq.answer && faq.answer.trim()) {
      faqInjection += `A: (Use this information in your answer: ${faq.answer})\n\n`;
    } else {
      faqInjection += `A: [Write a complete, accurate answer]\n\n`;
    }
  });
}

// ─── STRUCTURE ENFORCEMENT (headings) ────────────────────────────────────────
const creativeBrief = input.creative_brief || '';
let briefEnforcerInjection = '';
if (creativeBrief) {
  briefEnforcerInjection = `### CREATIVE BRIEF STRUCTURE (MANDATORY)

You MUST follow the structural outline below. Do not invent your own structure.

- Write the article conforming strictly to the content outline in the brief.
- Use the exact H2 headings specified — do not add, remove, or reorder them.
- Do NOT invent your own H2 headings if the outline already specifies them.

`;
  if (briefHeadings.length > 0) {
    briefEnforcerInjection += `MANDATORY HEADING ORDER — USE THESE EXACT H2s:\n`;
    briefHeadings.forEach((h, i) => {
      briefEnforcerInjection += `${i + 1}. ${h}\n`;
    });
    briefEnforcerInjection += `\nDo not add, remove, or reorder these headings.\n`;
  }
}

// ─── GLOBAL RULES INJECTION ───────────────────────────────────────────────────
const globalRulesInjection = `### GLOBAL EDITORIAL RULES (NON-NEGOTIABLE)

These rules apply to every article regardless of the brief. Each violation is unacceptable:

${GLOBAL_RULES.map((r, i) => `${i + 1}. ${r}`).join('\n')}
`;

// ─── BRIEF-SPECIFIC CUSTOM RULES INJECTION ───────────────────────────────────
let customRulesInjection = '';
if (briefCustomRules.length > 0) {
  customRulesInjection = `### BRIEF-SPECIFIC RULES (MANDATORY)

The following rules were explicitly specified in the creative brief. Every single one must be followed exactly:

${briefCustomRules.map((r, i) => `${i + 1}. ${r}`).join('\n')}
`;
}

// ─── TONE INJECTION ───────────────────────────────────────────────────────────
const toneSource = briefTone || input.tone || '';
let briefAuthorityPreamble = '';
if (toneSource) {
  briefAuthorityPreamble = `Tone & Voice: ${toneSource}. Maintain this voice consistently from the first sentence to the last. Do not shift tone mid-article.`;
}

// ─── CLIENT FIRST PARAGRAPH ───────────────────────────────────────────────────
let firstParagraphInjection = '';
if (input.client_name) {
  firstParagraphInjection = `The opening paragraph MUST organically mention the client (${input.client_name}) within the first two sentences. Do NOT use "the company", "the brand", or "they" as a substitute.`;
}

// ─── SECONDARY / SEMANTIC KEYWORDS ───────────────────────────────────────────
let secondaryKeywordChecklist = '';
if (secondary.length > 0 || semantic.length > 0) {
  secondaryKeywordChecklist = '### SUPPLEMENTARY KEYWORDS (weave naturally — do not force):\n';
  if (secondary.length > 0) {
    secondaryKeywordChecklist += 'Secondary Keywords:\n' + secondary.map(k => '- ' + k).join('\n') + '\n\n';
  }
  if (semantic.length > 0) {
    secondaryKeywordChecklist += 'Semantic Themes:\n' + semantic.map(s => '- ' + s).join('\n') + '\n';
  }
}



// ─── EEAT INJECTION ───────────────────────────────────────────────────────────
const eeatPromptInjection = `### E-E-A-T SIGNALS (Experience, Expertise, Authoritativeness, Trustworthiness)

Write with demonstrable expertise. Signal experience through specificity — real scenarios, precise details, concrete outcomes.
For medical/legal/financial topics: only cite named primary sources (PubMed, official .gov/.org, peer-reviewed journals).
Never use vague authority phrases like "experts say", "studies show", "research reveals" without a named source + URL.
Fabricated physician quotes or fake clinical statistics are grounds for immediate rejection.`;

// ─── STYLE INJECTION ─────────────────────────────────────────────────────────
const stylePromptInjection = `### STYLE ENFORCEMENT (MANDATORY)

- Do NOT use em-dashes (—). Replace with commas, periods, or parentheses.
- Avoid: "journey", "navigate", "navigating", "seamless", "seamlessly"
- Avoid: "in the ever-changing landscape of", "in the ever-evolving terrain of"
- Restrict: "comprehensive", "integrate", "integrated"
- Avoid correlative constructions: "not only … but also", "not just … but also"
- Keep sentences concise. Keep paragraphs to 3-4 sentences maximum.
- Writing must feel like trusted professional advice, not marketing copy.`;

// ─── SYSTEM INJECTION ────────────────────────────────────────────────────────
const systemPromptInjection = `### GLOBAL RULES (NON-NEGOTIABLE)

1. Client name appears ONLY in the closing paragraph — never in the opening.
2. Write in first-person brand voice (we/our) for the client.
3. Every article must start with Meta Title: and Meta Description: before the H1.
4. No fabricated statistics, hallucinated studies, or invented clinical data.
5. No em-dashes, no journey/navigate/seamless language.
6. Word count must be within 10% of the target.`;

// ─── STRUCTURE INJECTION ─────────────────────────────────────────────────────
const structurePromptInjection = `### STRUCTURAL REQUIREMENTS

- Article must begin with: Meta Title: [max 60 chars] and Meta Description: [140-160 chars]
- H1 must contain the primary keyword
- Minimum one H2 must contain the primary keyword or a close variation
- Primary keyword must appear in the first 100 words (after Meta Title/Description)
- Primary keyword must appear in the conclusion
- All FAQ questions must use H3 tags (### in markdown)
- Never skip heading levels (H1 → H2 → H3 only)`;


return {
  json: {
    primary_keyword_joined:         primary,
    secondary_keywords_arr:         secondary,
    semantic_themes_arr:            semantic,
    brief_enforcer_injection:       briefEnforcerInjection,
    faq_injection:                  faqInjection,
    global_rules_injection:         globalRulesInjection,
    custom_rules_injection:         customRulesInjection,
    first_paragraph_client_injection: firstParagraphInjection,
    secondary_keyword_checklist:    secondaryKeywordChecklist,
    eeat_prompt_injection:      eeatPromptInjection,
    style_prompt_injection:     stylePromptInjection,
    system_prompt_injection:    systemPromptInjection,
    structure_prompt_injection: structurePromptInjection,
    brief_authority_preamble:       briefAuthorityPreamble,
    detected_brief_headings:        briefHeadings,
    detected_faqs:                  faqArray,
    detected_custom_rules:          briefCustomRules,
  }
};

// Keyword Validator v3 — Expert-weighted scoring
const content = $input.first().json.content || $input.first().json.text || '';
const input = $('Webhook1').first().json.body;

const primary = (input.primary_keywords || '').trim();
function parseKeywords(raw) {
  if (!raw || typeof raw !== 'string') return [];
  return raw.split(',').map(k => k.trim()).filter(k => k.length > 0);
}
function escapeRegex(str) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

if (!primary) {
  return [{ json: { score: 0, passed: false, issues: ['No primary keyword provided'] } }];
}

const allSecondary = [...parseKeywords(input.secondary_keywords), ...parseKeywords(input.semantic_theme)]
  .filter((v, i, a) => a.indexOf(v) === i);

const lower = content.toLowerCase();
const primaryLower = primary.toLowerCase();
const plainText = content.replace(/<[^>]*>/g, '').replace(/[#*_]/g, '');
const words = plainText.split(/\s+/);

let score = 0;
const issues = [];

// 1. H1 contains primary keyword (20 pts — highest SEO value per Backlinko/Google)
const h1Match = content.match(/<h1[^>]*>(.*?)<\/h1>/i) || content.match(/^#\s+(.+)$/m);
const h1Text = h1Match ? h1Match[1].toLowerCase() : '';
if (!h1Match) {
  issues.push('MISSING H1 TAG');
} else if (h1Text.includes(primaryLower)) {
  score += 20;
} else {
  issues.push('Primary keyword NOT in H1. Found: "' + (h1Match[1] || '').substring(0, 60) + '"');
}

// 2. Primary in first 100 words (15 pts — Backlinko: "still makes a difference")
const first100 = words.slice(0, 100).join(' ').toLowerCase();
if (first100.includes(primaryLower)) {
  score += 15;
} else {
  issues.push('Primary keyword NOT in first 100 words');
}

// 3. Primary (or close variation) in at least one H2 (15 pts)
const h2Matches = content.match(/<h2[^>]*>(.*?)<\/h2>/gi) || content.match(/^##\s+(.+)$/gm) || [];
const h2Texts = h2Matches.map(h => h.replace(/<[^>]*>/g, '').replace(/^##\s+/, '').toLowerCase());
const primaryWords = primaryLower.split(/\s+/);
const minMatchWords = Math.ceil(primaryWords.length * 0.6);
const primaryInH2 = h2Texts.some(h => {
  if (h.includes(primaryLower)) return true;
  const matchedWords = primaryWords.filter(w => h.includes(w));
  return matchedWords.length >= minMatchWords;
});
if (primaryInH2) {
  score += 15;
} else {
  issues.push('Primary keyword (or variation) NOT in any H2');
}

// 4. Primary in conclusion (10 pts)
const paragraphs = plainText.split(/\n\n+/).filter(p => p.trim().length > 30);
const lastPara = paragraphs.length > 0 ? paragraphs[paragraphs.length - 1].toLowerCase() : '';
if (lastPara.includes(primaryLower)) {
  score += 10;
} else {
  issues.push('Primary keyword NOT in conclusion');
}

// 5. Keyword frequency check (10 pts — Backlinko: ~8 per 3200 words)
const primaryRegex = new RegExp(escapeRegex(primaryLower), 'gi');
const primaryCount = (lower.match(primaryRegex) || []).length;
const wordCount = words.length;
const expectedFreq = Math.max(3, Math.round((wordCount / 3200) * 8));
if (primaryCount >= expectedFreq - 1 && primaryCount <= expectedFreq * 2) {
  score += 10;
} else if (primaryCount >= 2) {
  score += 5;
  issues.push('Keyword frequency: ' + primaryCount + 'x (target: ~' + expectedFreq + 'x)');
} else {
  issues.push('Keyword used only ' + primaryCount + 'x (target: ~' + expectedFreq + 'x)');
}

// 6. All secondary/semantic keywords present (25 pts)
const secondaryResults = allSecondary.map(kw => ({
  keyword: kw,
  found: lower.includes(kw.toLowerCase())
}));
const secondaryFound = secondaryResults.filter(s => s.found).length;
const secondaryTotal = allSecondary.length || 1;
score += Math.round((secondaryFound / secondaryTotal) * 25);
const missing = secondaryResults.filter(s => !s.found).map(s => s.keyword);
if (missing.length > 0) {
  issues.push('MISSING secondary/semantic: ' + missing.join(' | '));
}

// 7. H2 keyword distribution (5 pts bonus — Surfer SEO best practice)
const keywordsInH2 = allSecondary.filter(kw =>
  h2Texts.some(h => h.includes(kw.toLowerCase()))
);
if (keywordsInH2.length >= 1) {
  score += 5;
}

// 8. Keyword bolding penalty (informational)
const boldedKeyword = content.match(new RegExp('\\*\\*[^*]*' + escapeRegex(primaryLower) + '[^*]*\\*\\*', 'i'));
if (boldedKeyword) {
  issues.push('WARNING: Primary keyword is bolded in body text');
}

const finalScore = Math.min(100, score);
const passed = finalScore >= 60 && h1Text.includes(primaryLower) && first100.includes(primaryLower);

return [{ json: {
  score: finalScore,
  passed,
  issues,
  checks: {
    primaryInH1: h1Text.includes(primaryLower),
    primaryInFirst100: first100.includes(primaryLower),
    primaryInH2: primaryInH2,
    primaryInConclusion: lastPara.includes(primaryLower),
    frequency: primaryCount + 'x (target: ~' + expectedFreq + 'x)',
    secondaryCoverage: secondaryFound + '/' + allSecondary.length,
    missingKeywords: missing,
    secondaryInH2s: keywordsInH2
  }
}}];

